import React from 'react';
import { useState } from 'react';
import { submitQuote } from '../../services/api';

const Hero = ({ content = {} }) => {
  const {
    title = 'Devis décennale Électricien',
    subtitle = 'Assurance décennale électricien',
    ctaText = 'Devis Gratuit'
  } = content;

  const [formData, setFormData] = useState({
    nom: '',
    email: '',
    tele: '',
    entreprise: '',
    statut: '',
    chiffreAffaires: ''
  });
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      await submitQuote(formData);
      setSuccess(true);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="bg-yellow-500 py-12">
      <div className="container mx-auto px-4">
        <div className="grid lg:grid-cols-2 gap-8 items-center">
          <div className="text-white">
            <h1 className="text-3xl md:text-4xl font-bold mb-2">{title}</h1>
            <p className="text-xl mb-6 text-yellow-100">{subtitle}</p>
            <p className="text-lg mb-4">01 82 83 48 00</p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-lg">
            {success ? (
              <div className="text-center py-8">
                <div className="w-16 h-16 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4">
                  <i className="fas fa-check text-white text-2xl"></i>
                </div>
                <h2 className="text-2xl font-bold text-gray-800 mb-2">Merci !</h2>
                <p className="text-gray-600">Votre demande a été envoyée. Un expert vous contactera rapidement.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-4">
                <h2 className="text-xl font-bold text-gray-800 mb-4">{ctaText}</h2>

                <p className="text-sm text-gray-500 mb-4">
                  <i className="fas fa-lock mr-1"></i> Vos données sont protégées. Conformément au RGPD.
                </p>

                {error && (
                  <div className="bg-red-100 text-red-700 px-4 py-2 rounded">{error}</div>
                )}

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Nom complet *</label>
                  <input
                    type="text"
                    name="nom"
                    value={formData.nom}
                    onChange={handleChange}
                    placeholder="Votre nom"
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                    required
                  />
                </div>

                <div className="grid md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Email *</label>
                    <input
                      type="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      placeholder="votre@email.com"
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                      required
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Téléphone *</label>
                    <input
                      type="tel"
                      name="tele"
                      value={formData.tele}
                      onChange={handleChange}
                      placeholder="06 12 34 56 78"
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                      required
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Entreprise</label>
                  <input
                    type="text"
                    name="entreprise"
                    value={formData.entreprise}
                    onChange={handleChange}
                    placeholder="Nom de votre société"
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                  />
                </div>

                <div className="grid md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Statut *</label>
                    <select
                      name="statut"
                      value={formData.statut}
                      onChange={handleChange}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                      required
                    >
                      <option value="">Sélectionner...</option>
                      <option value="auto-entrepreneur">Auto-entrepreneur</option>
                      <option value="ei">Entreprise Individuelle</option>
                      <option value="eurl">EURL</option>
                      <option value="sarl">SARL</option>
                      <option value="sas">SAS</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Chiffre d'affaires</label>
                    <select
                      name="chiffreAffaires"
                      value={formData.chiffreAffaires}
                      onChange={handleChange}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500 outline-none"
                    >
                      <option value="">Sélectionner...</option>
                      <option value="0-30k">Moins de 30 000€</option>
                      <option value="30-60k">30 000€ - 60 000€</option>
                      <option value="60-100k">60 000€ - 100 000€</option>
                      <option value="100k+">Plus de 100 000€</option>
                    </select>
                  </div>
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full bg-yellow-500 text-white font-bold py-4 rounded-lg hover:bg-yellow-600 transition-colors disabled:opacity-50"
                >
                  {loading ? 'Envoi...' : 'Obtenir mon devis'}
                </button>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
